# chaos/action_item_tracker.py
"""Tracks chaos experiment action items and their SLA compliance."""
from datetime import date, timedelta
import json
from pathlib import Path

SLA_BY_PRIORITY = {
    "P0": timedelta(weeks=1),
    "P1": timedelta(weeks=4),
    "P2": timedelta(weeks=12),
    "P3": timedelta(weeks=26),
}

def load_open_items(reports_dir: str) -> list[dict]:
    items = []
    for report_file in Path(reports_dir).glob("*/report.json"):
        report = json.loads(report_file.read_text())
        for finding in report.get("findings", []):
            if finding.get("resolution_status") in ("open", "in_progress"):
                finding["experiment_id"] = report["experiment_id"]
                finding["experiment_date"] = report["date"]
                items.append(finding)
    return items

def check_sla_compliance(items: list[dict], as_of: date = None) -> list[dict]:
    as_of = as_of or date.today()
    for item in items:
        priority = item.get("priority", "P3")
        due = date.fromisoformat(item.get("due_date", "2099-01-01"))
        item["sla_deadline"] = due
        item["is_overdue"] = due < as_of
        item["days_overdue"] = (as_of - due).days if item["is_overdue"] else 0
    return sorted(items, key=lambda i: (not i["is_overdue"], i.get("priority", "P3")))

def sla_summary(items: list[dict]) -> dict:
    overdue = [i for i in items if i.get("is_overdue")]
    return {
        "total_open": len(items),
        "overdue": len(overdue),
        "compliance_rate": 1 - len(overdue) / max(len(items), 1),
        "overdue_by_priority": {
            p: sum(1 for i in overdue if i.get("priority") == p)
            for p in ("P0", "P1", "P2", "P3")
        },
    }
